import{Base}from"./Base.js";class WithParams extends Base{constructor(){super(),this.c=this.context(),this.params={},this.conversions={beats:value=>value*this.beat}}mirrorParams(params){this.params=Object.assign(this.params,params);for(const name of Object.keys(this.params))this.setParam(name,this[name]);this.fire("blamparams",{elem:this,params:this.params},this)}setParam(name,value){let param=this.params[name],time=param.time||this.getTime();delete param.time;let ramp=param.ramp;delete param.ramp;let converted=this.convertValue(name,value);isFinite(converted)?ramp?param.linearRampToValueAtTime(converted,time+ramp*this.beat):param.setTargetAtTime(converted,time,.005):this.params[name][name]=value}attributeChangedCallback(name,_,value){this.params[name]&&this.setParam(name,value)}}export{WithParams};